// ==========================================
// 全兼容最终版：支持圆形/异形填充 + 强制拉伸覆盖 + 解决焦点报错
// ==========================================

var debugMode = false;
var GLOBAL_SOURCE_INFO = null;

/**
 * 锁定素材源：确保无论打开多少样机，都只用第一张选中的地毯图
 */
function getGlobalSource() {
  if (GLOBAL_SOURCE_INFO == null) {
    if (app.documents.length === 0) {
      throw new Error('请先在 PS 中打开地毯素材图！');
    }
    // 锁定当前最前面的文档
    var doc = app.activeDocument;
    GLOBAL_SOURCE_INFO = {
      file: new File(doc.fullName),
      width: doc.width.as('px'),
      height: doc.height.as('px')
    };
  }
  return GLOBAL_SOURCE_INFO;
}

/**
/**
 * 主入口：处理样机逻辑
 * @param {string} pngPath - 样机 PSD 路径
 * @param {string} layerName - 智能对象图层名（null 则处理所有）
 * @param {string} rotateNum - 旋转角度
 * @param {string} materialPath - 素材图片路径（新增）
 * @param {string} outputFolder - 输出文件夹路径（新增）
 */
function embedImageToMockup(pngPath, layerName, rotateNum, materialPath, outputFolder) {
  // 预处理旋转参数
  if (rotateNum == 'null' || rotateNum == null) {
    var txtFile = new File(pngPath.replace(/\.[^.]+$/, '.txt'));
    if (txtFile.exists) {
      txtFile.encoding = 'UTF-8';
      txtFile.open('r');
      rotateNum = txtFile.read();
      txtFile.close();
    } else {
      rotateNum = '0';
    }
  }
  var rotateNumArr = rotateNum.toString().split(',');
  var finalRotate = Number(rotateNumArr[0]);

  var originalRulerUnits = app.preferences.rulerUnits;
  app.preferences.rulerUnits = Units.PIXELS;
  app.displayDialogs = DialogModes.NO;

  var mockupDoc = null;

  try {
    // 根据是否传入 materialPath 决定素材来源
    var sourceInfo;
    if (materialPath && materialPath !== 'null') {
      var materialFile = new File(materialPath);
      if (!materialFile.exists) throw new Error('找不到素材文件: ' + materialPath);
      // 打开素材图获取尺寸
      var materialDoc = app.open(materialFile);
      sourceInfo = {
        file: materialFile,
        width: materialDoc.width.as('px'),
        height: materialDoc.height.as('px')
      };
      materialDoc.close(SaveOptions.DONOTSAVECHANGES);
    } else {
      sourceInfo = getGlobalSource();
    }

    var psdFile = new File(pngPath.replace(/\.[^.]+$/, '.psd'));
    if (!psdFile.exists) throw new Error('找不到样机文件: ' + psdFile.fullName);

    // 1. 打开样机并强制激活
    mockupDoc = app.open(psdFile);
    app.activeDocument = mockupDoc;

    // 2. 寻找匹配的智能对象图层
    var smartLayers = [];
    findSmartLayers(mockupDoc, smartLayers, layerName);
    if (smartLayers.length === 0) {
      findSmartLayers(mockupDoc, smartLayers, null);
    }

    // 3. 循环处理
    for (var i = 0; i < smartLayers.length; i++) {
      processSmartObject(mockupDoc, smartLayers[i], sourceInfo, finalRotate);
    }

    // 4. 导出 PNG，输出到指定文件夹
    var psdBaseName = psdFile.name.replace(/\.[^.]+$/, '');
    var materialBaseName = sourceInfo.file.name.replace(/\.[^.]+$/, '');
    var outDir = outputFolder && outputFolder !== 'null' ? outputFolder : Folder.desktop.fsName;
    var outFile = new File(outDir + '/' + materialBaseName + '_' + psdBaseName + '.png');

    var pngOpts = new ExportOptionsSaveForWeb();
    pngOpts.format = SaveDocumentType.PNG;
    pngOpts.PNG8 = false;
    pngOpts.transparency = true;
    pngOpts.interlaced = false;
    pngOpts.quality = 100;
    mockupDoc.exportDocument(outFile, ExportType.SAVEFORWEB, pngOpts);

    mockupDoc.close(SaveOptions.DONOTSAVECHANGES);
    app.preferences.rulerUnits = originalRulerUnits;
    return 'true';
  } catch (e) {
    if (mockupDoc) {
      try {
        mockupDoc.close(SaveOptions.DONOTSAVECHANGES);
      } catch (ex) {}
    }
    app.preferences.rulerUnits = originalRulerUnits;
    return 'false:' + e.message;
  }
}

/**
 * 递归查找图层
 */
function findSmartLayers(parent, collector, layerName) {
  for (var i = 0; i < parent.layers.length; i++) {
    var layer = parent.layers[i];
    if (layer.typename === 'LayerSet') {
      findSmartLayers(layer, collector, layerName);
    } else if (layer.kind === LayerKind.SMARTOBJECT) {
      if (!layerName || layer.name === layerName) collector.push(layer);
    }
  }
}

/**
 * 核心：进入智能对象并执行替换
 */
function processSmartObject(parentDoc, targetLayer, sourceInfo, rotateNum) {
  // 确保父文档处于焦点
  app.activeDocument = parentDoc;
  parentDoc.activeLayer = targetLayer;

  // 使用底层指令打开智能对象窗口 (.psb)
  var idplacedLayerEditContents = stringIDToTypeID('placedLayerEditContents');
  executeAction(idplacedLayerEditContents, new ActionDescriptor(), DialogModes.NO);

  var smartDoc = app.activeDocument;

  // 检查嵌套（针对那种“样机套样机”的多层结构）
  var innerSmartLayers = [];
  findSmartLayers(smartDoc, innerSmartLayers, null);

  if (innerSmartLayers.length > 0) {
    for (var j = 0; j < innerSmartLayers.length; j++) {
      processSmartObject(smartDoc, innerSmartLayers[j], sourceInfo, rotateNum);
    }
  } else {
    // 执行填充逻辑
    replaceAndFillCanvas(smartDoc, sourceInfo, rotateNum);
    try {
      smartDoc.flatten();
    } catch (e) {}
  }

  // 保存 PSB 内容（智能对象必须保存才能生效），关闭窗口
  smartDoc.save();
  smartDoc.close(SaveOptions.DONOTSAVECHANGES);
}

/**
 * 关键修正：全形状兼容填充算法（拉伸以消除所有空白）
 */
function replaceAndFillCanvas(targetDoc, sourceInfo, rotateNum) {
  // 再次强制激活当前文档，防止多窗口切换导致的焦点丢失
  app.activeDocument = targetDoc;

  // 1. 深度清理：确保背景干净
  var tempLayer = targetDoc.artLayers.add();
  tempLayer.name = 'CLEANUP_STUB';
  for (var i = targetDoc.layers.length - 1; i >= 0; i--) {
    var l = targetDoc.layers[i];
    if (l.name !== 'CLEANUP_STUB') {
      l.locked = false;
      l.remove();
    }
  }

  // 2. 嵌入素材
  var desc = new ActionDescriptor();
  desc.putPath(charIDToTypeID('null'), sourceInfo.file);
  executeAction(charIDToTypeID('Plc '), desc, DialogModes.NO);

  var pastedLayer = targetDoc.activeLayer;
  try {
    targetDoc.layers['CLEANUP_STUB'].remove();
  } catch (e) {}

  // 3. 获取画布的物理像素
  var docW = targetDoc.width.as('px');
  var docH = targetDoc.height.as('px');

  // 4. 处理旋转：必须在缩放前旋转
  if (rotateNum != 0) {
    pastedLayer.rotate(rotateNum, AnchorPosition.MIDDLECENTER);
  }

  // 5. 【全形状填充逻辑】
  // 获取旋转后图片的真实边界（像素）
  var b = pastedLayer.bounds;
  var curW = b[2].as('px') - b[0].as('px');
  var curH = b[3].as('px') - b[1].as('px');

  // 计算 X 和 Y 的独立缩放系数
  // 这种拉伸模式可以确保无论样机是圆是方，图片都会填满整个“容器”
  var scaleX = (docW / curW) * 100;
  var scaleY = (docH / curH) * 100;

  // 执行非等比例缩放（彻底消除空白边）
  pastedLayer.resize(scaleX, scaleY, AnchorPosition.MIDDLECENTER);

  // 6. 居中对齐：确保边缘对齐到 0,0 坐标
  var nb = pastedLayer.bounds;
  var newW = nb[2].as('px') - nb[0].as('px');
  var newH = nb[3].as('px') - nb[1].as('px');

  var offX = (docW - newW) / 2 - nb[0].as('px');
  var offY = (docH - newH) / 2 - nb[1].as('px');
  pastedLayer.translate(offX, offY);
}

// ==========================================
// Tool Page Tools — 新增工具函数
// ==========================================

/**
 * 清除水印：对当前选区执行内容识别填充
 * @returns {string} 'true' | 'false:错误描述'
 */
function removeWatermark() {
  try {
    if (app.documents.length === 0) return 'false:请先在 PS 中打开一个文档';
    var doc = app.activeDocument;
    try {
      doc.selection.bounds;
    } catch (e) {
      return 'false:请先在 PS 中圈选水印区域';
    }

    // 自动找到最底层的可编辑像素图层（跳过文字层、调整层等）
    var targetLayer = null;
    for (var i = doc.layers.length - 1; i >= 0; i--) {
      var l = doc.layers[i];
      if (l.kind === LayerKind.NORMAL || l.kind === LayerKind.SMARTOBJECT || l.isBackgroundLayer) {
        targetLayer = l;
        break;
      }
    }
    if (!targetLayer) return 'false:找不到可编辑的像素图层，请在图层面板选中图片图层';

    doc.activeLayer = targetLayer;
    var layer = doc.activeLayer;

    // 背景层解锁
    if (layer.isBackgroundLayer) {
      layer.isBackgroundLayer = false;
      layer = doc.activeLayer;
    }

    // 智能对象栅格化
    if (layer.kind === LayerKind.SMARTOBJECT) {
      layer.rasterize(RasterizeType.ENTIRELAYER);
      layer = doc.activeLayer;
    }

    try {
      layer.pixelsLocked = false;
    } catch (e2) {}
    try {
      layer.allLocked = false;
    } catch (e2) {}
    layer.visible = true;

    // 执行内容识别填充
    var desc = new ActionDescriptor();
    desc.putEnumerated(charIDToTypeID('Usng'), charIDToTypeID('FlCn'), stringIDToTypeID('contentAware'));
    desc.putUnitDouble(charIDToTypeID('Opct'), charIDToTypeID('#Prc'), 100);
    desc.putEnumerated(charIDToTypeID('Md  '), charIDToTypeID('BlnM'), charIDToTypeID('Nrml'));
    executeAction(charIDToTypeID('Fl  '), desc, DialogModes.NO);
    doc.selection.deselect();
    return 'true';
  } catch (e) {
    return 'false:' + e.message;
  }
}

/**
 * 添加文字水印：在当前选区中心创建文字图层
 * @param {string} text 水印文字
 * @returns {string} 'true' | 'false:错误描述'
 */
function addWatermarkText(text, position) {
  try {
    if (app.documents.length === 0) return 'false:请先在 PS 中打开一个文档';
    var doc = app.activeDocument;
    var origUnits = app.preferences.rulerUnits;
    app.preferences.rulerUnits = Units.PIXELS;

    var docW = doc.width.as('px');
    var docH = doc.height.as('px');
    var fontSize = Math.max(48, Math.round(Math.min(docW, docH) / 10));
    var margin = Math.round(Math.min(docW, docH) * 0.03);

    var textLayer = doc.artLayers.add();
    textLayer.kind = LayerKind.TEXT;
    var textItem = textLayer.textItem;
    textItem.contents = decodeURIComponent(text);
    textItem.size = new UnitValue(fontSize, 'px');
    textItem.color = (function () {
      var c = new SolidColor();
      c.rgb.red = 255;
      c.rgb.green = 255;
      c.rgb.blue = 255;
      return c;
    })();
    // 先放到 (0,0) 获取文字实际尺寸
    textItem.position = [new UnitValue(0, 'px'), new UnitValue(fontSize, 'px')];
    var b = textLayer.bounds;
    var tw = b[2].as('px') - b[0].as('px');
    var th = b[3].as('px') - b[1].as('px');

    // 根据位置参数计算坐标
    var x, y;
    var pos = position || 'bottom-right';
    if (pos === 'top-left') {
      x = margin;
      y = margin + th;
    } else if (pos === 'top-right') {
      x = docW - tw - margin;
      y = margin + th;
    } else if (pos === 'bottom-left') {
      x = margin;
      y = docH - margin;
    } else {
      x = docW - tw - margin;
      y = docH - margin;
    }

    textItem.position = [new UnitValue(x, 'px'), new UnitValue(y, 'px')];
    textLayer.opacity = 60;
    textLayer.name = '水印 - ' + decodeURIComponent(text);

    app.preferences.rulerUnits = origUnits;
    return 'true';
  } catch (e) {
    return 'false:' + e.message;
  }
}

/**
 * 另存为 JPG（质量 12）
 * @param {string} folderPath 保存文件夹路径
 * @param {string} fileName 文件名（不含扩展名）
 * @returns {string} 'true' | 'false:错误描述'
 */
function saveAsJpg(folderPath, fileName) {
  try {
    if (app.documents.length === 0) return 'false:请先在 PS 中打开一个文档';
    var doc = app.activeDocument;
    var folder = new Folder(decodeURIComponent(folderPath));
    if (!folder.exists) folder.create();
    var file = new File(folder.fsName + '/' + decodeURIComponent(fileName) + '.jpg');
    var opts = new JPEGSaveOptions();
    opts.quality = 12;
    opts.embedColorProfile = true;
    opts.formatOptions = FormatOptions.STANDARDBASELINE;
    doc.saveAs(file, opts, true, Extension.LOWERCASE);
    return 'true';
  } catch (e) {
    return 'false:' + e.message;
  }
}

/**
 * 调整文档尺寸（等比例）
 * @param {number} width 目标宽度（px）
 * @param {number} height 目标高度（px）
 * @returns {string} 'true' | 'false:错误描述'
 */
function resizeDocument(width, height) {
  try {
    if (app.documents.length === 0) return 'false:请先在 PS 中打开一个文档';
    var doc = app.activeDocument;
    var origUnits = app.preferences.rulerUnits;
    app.preferences.rulerUnits = Units.PIXELS;
    doc.resizeImage(new UnitValue(Number(width), 'px'), new UnitValue(Number(height), 'px'), doc.resolution, ResampleMethod.BICUBIC);
    app.preferences.rulerUnits = origUnits;
    return 'true';
  } catch (e) {
    return 'false:' + e.message;
  }
}

/**
 * 旋转画布
 * @param {number} angle 旋转角度（度）
 * @returns {string} 'true' | 'false:错误描述'
 */
function rotateCanvas(angle) {
  try {
    if (app.documents.length === 0) return 'false:请先在 PS 中打开一个文档';
    var doc = app.activeDocument;
    doc.rotateCanvas(Number(angle));
    return 'true';
  } catch (e) {
    return 'false:' + e.message;
  }
}

/**
 * 导出 PSD 为指定尺寸 PNG
 * @param {string} psdPath PSD 文件路径
 * @param {string} destPath 目标 PNG 文件完整路径
 * @param {number} size 目标长边尺寸（px）
 * @returns {string} 'true' | 'false:错误描述'
 */
function exportPsdAsPng(psdPath, destPath, size) {
  var doc = null;
  var origUnits = app.preferences.rulerUnits;
  try {
    var psdFile = new File(decodeURIComponent(psdPath));
    if (!psdFile.exists) return 'false:找不到文件: ' + psdPath;
    doc = app.open(psdFile);
    app.preferences.rulerUnits = Units.PIXELS;
    var w = doc.width.as('px');
    var h = doc.height.as('px');
    var scale = (Number(size) / Math.max(w, h)) * 100;
    doc.resizeImage(null, null, doc.resolution, ResampleMethod.BICUBIC, scale);
    var outFile = new File(decodeURIComponent(destPath));
    var pngOpts = new ExportOptionsSaveForWeb();
    pngOpts.format = SaveDocumentType.PNG;
    pngOpts.PNG8 = false;
    pngOpts.transparency = true;
    pngOpts.quality = 100;
    doc.exportDocument(outFile, ExportType.SAVEFORWEB, pngOpts);
    doc.close(SaveOptions.DONOTSAVECHANGES);
    app.preferences.rulerUnits = origUnits;
    return 'true';
  } catch (e) {
    if (doc) {
      try {
        doc.close(SaveOptions.DONOTSAVECHANGES);
      } catch (e2) {}
    }
    app.preferences.rulerUnits = origUnits;
    return 'false:' + e.message;
  }
}

/**
 * 对选区应用曲线和色阶调整图层（光影自动匹配）
 * @returns {string} 'true' | 'false:错误描述'
 */
function applyLightingAdjustment() {
  try {
    if (app.documents.length === 0) return 'false:请先在 PS 中打开一个文档';
    var doc = app.activeDocument;
    try {
      doc.selection.bounds;
    } catch (e) {
      return 'false:请先在 PS 中圈选目标区域';
    }

    // PS 2018 兼容：通过菜单 ID 触发新建调整图层
    // 曲线：Image > Adjustments > Curves 对应的调整图层菜单 ID
    // 新建曲线调整图层 (Layer > New Adjustment Layer > Curves)
    app.runMenuItem(stringIDToTypeID('curves'));

    // 新建色阶调整图层
    app.runMenuItem(stringIDToTypeID('levels'));

    return 'true';
  } catch (e) {
    return 'false:' + e.message;
  }
}

/**
 * 图片高清处理：放大2倍 + 智能锐化，提升图片清晰度
 * 兼容 PS CC 2018
 * @returns {string} 'true' | 'false:错误描述'
 */
function enhanceImageQuality() {
  try {
    if (app.documents.length === 0) return 'false:请先在 PS 中打开一个文档';
    var doc = app.activeDocument;
    var originalRulerUnits = app.preferences.rulerUnits;
    app.preferences.rulerUnits = Units.PIXELS;

    var origW = doc.width.as('px');
    var origH = doc.height.as('px');
    var newW = origW * 2;
    var newH = origH * 2;

    // 放大2倍，使用保留细节重采样（PS CC 2018 支持）
    var idImgS = charIDToTypeID('ImgS');
    var desc = new ActionDescriptor();
    desc.putUnitDouble(charIDToTypeID('Wdth'), charIDToTypeID('#Pxl'), newW);
    desc.putUnitDouble(charIDToTypeID('Hght'), charIDToTypeID('#Pxl'), newH);
    desc.putBoolean(charIDToTypeID('Cnsn'), true); // 约束比例
    // 重采样方式：保留细节 2.0 (stringID: 'preserveDetailsUpscale')
    // PS 2018 fallback: 使用双三次插值
    try {
      desc.putEnumerated(charIDToTypeID('Intr'), charIDToTypeID('Intr'), stringIDToTypeID('preserveDetailsUpscale'));
    } catch (e) {
      desc.putEnumerated(
        charIDToTypeID('Intr'),
        charIDToTypeID('Intr'),
        charIDToTypeID('Bcbc') // 双三次插值
      );
    }
    executeAction(idImgS, desc, DialogModes.NO);

    // 应用智能锐化（Unsharp Mask）
    var idUsrM = stringIDToTypeID('unsharpMask');
    var sharpDesc = new ActionDescriptor();
    sharpDesc.putUnitDouble(charIDToTypeID('Amnt'), charIDToTypeID('#Prc'), 80); // 数量 80%
    sharpDesc.putUnitDouble(charIDToTypeID('Rds '), charIDToTypeID('#Pxl'), 1.0); // 半径 1px
    sharpDesc.putInteger(charIDToTypeID('Thsh'), 3); // 阈值 3
    executeAction(idUsrM, sharpDesc, DialogModes.NO);

    app.preferences.rulerUnits = originalRulerUnits;
    return 'true';
  } catch (e) {
    return 'false:' + e.message;
  }
}
